mapper.select:
select count(*)
from emp e
left join dept d on e.dept_id = d.id


        and e.name like concat('%', #{name}, '%')


        and e.gender = #{gender}


        and e.entry_date  >=  #{begin}


        and e.entry_date  <=  #{end}

select e.*, d.name deptName
from emp e
left join dept d on e.dept_id = d.id


        and e.name like concat('%', #{name}, '%')


        and e.gender = #{gender}


        and e.entry_date  >=  #{begin}


        and e.entry_date  <=  #{end}


order by e.update_time desc
limit #{start}, #{pageSize}
